# MRQAP結果をgtテーブルで整理
mrqap_coefs <- mrqap_fit$coefficients
mrqap_names <- c("(Intercept)", "Same Class", "Proficiency Gap")

mrqap_table <- tibble(
  変数 = mrqap_names,
  推定値 = round(mrqap_coefs, 4),
  `QAP p値 (右側)` = round(c(
    mrqap_fit$pleeq[1],
    mrqap_fit$pgreq[2],
    mrqap_fit$pleeq[3]
  ), 4)
) %>%
  mutate(
    判定 = case_when(
      `QAP p値 (右側)` < 0.001 ~ "***",
      `QAP p値 (右側)` < 0.01  ~ "**",
      `QAP p値 (右側)` < 0.05  ~ "*",
      TRUE ~ "n.s."
    )
  )

mrqap_table %>%
  gt() %>%
  tab_header(
    title = "MRQAP回帰結果",
    subtitle = paste0("置換回数: 2000, 目的変数: 協働回数")
  ) %>%
  tab_source_note("p値は片側検定。Same Class は右側（正の効果）、Proficiency Gap は左側（負の効果）を検定。")
